// // This module compares two 8-bit numbers and outputs whether a is less than or equal to b
module comparator8bit(a, b, gt, eq, lt);
    input [7:0] a;
    input [7:0] b;
    output gt;
    output eq;
    output lt;

    assign gt = (a > b);
    assign eq = (a == b);
    assign lt = (a < b);
endmodule
